class Solution:
    def originalDigits(self, s: str) -> str:
        cnt = Counter(s)
        order = "zowtufxsgn"
        digits = "0123456789"
        uniq = "zowtufxg"
        ans = []
        for d, u in zip("02468", uniq):
            k = cnt[u]
            ans += [d] * k
            for c in ["zero","two","four","six","eight"][int(d)//2]:
                cnt[c] -= k
        for d, word in zip("3579", ["three","five","seven","nine"]):
            k = cnt[word[0]]
            ans += [d] * k
            for c in word: cnt[c] -= k
        ans += ["1"] * cnt["o"]
        return "".join(sorted(ans))

